const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});
const imageKey = binaryKeys.includes('image') ? 'image' : binaryKeys[0];
const image = imageKey ? item.binary[imageKey] : null;
if (!image?.data) {
  throw new Error('жңӘж”¶еҲ°ең–зүҮжӘ”жЎҲгҖӮHTML FormData ж¬„дҪҚи«Ӣе‘ҪеҗҚзӮә imageгҖӮ');
}

const body = item.json || {};
const operatorRaw = body.operator || body.operatorJson || '{}';
let operator = {};
try {
  operator = typeof operatorRaw === 'string' ? JSON.parse(operatorRaw) : operatorRaw;
} catch (error) {
  operator = {};
}

const prompt = `дҪ жҳҜиЈҪйҖ жҘӯгҖҢзҸҫе ҙиЈңж–ҷе–®гҖҚOCR иҲҮиіҮж–ҷзөҗж§ӢеҢ–еҠ©жүӢгҖӮи«ӢиҫЁиӯҳең–зүҮдёӯзҡ„е–®ж“ҡиіҮж–ҷпјҢеҡҙж јд»Ҙ JSON ж јејҸијёеҮәпјҢдёҚиҰҒијёеҮә markdown жЁҷиЁҳпјҲеҰӮ \`\`\`jsonпјүпјҢд№ҹдёҚиҰҒеҠ дёҠд»»дҪ•и§ЈйҮӢж–Үеӯ—гҖӮ

гҖҗдёҖгҖҒиіҮж–ҷж“·еҸ–ж ёеҝғйӮҸијҜгҖ‘
1. е…ЁеұҖй җеҲӨпјҡи«Ӣе…ҲжҺғжҸҸең–зүҮдёӯзҡ„иЎЁж јпјҢзўәиӘҚе…ұжңүе№ҫеҲ—жҳҺзҙ°пјҢдёҰе°Үж•ёеӯ—еЎ«е…Ҙ total_detected_rowsгҖӮ
2. жҸӣеҲ—еҲӨе®ҡпјҡеҸӘиҰҒжңүзҚЁз«Ӣзҡ„гҖҢе“ҒиҷҹгҖҚгҖҒгҖҢиҰҸж јгҖҚжҲ–гҖҢж•ёйҮҸгҖҚеҮәзҸҫпјҢеҚіиҰ–зӮәзҚЁз«Ӣзҡ„дёҖзӯҶжҳҺзҙ°пјҢеҝ…й ҲиҲҮдёҠдёӢеҲ—еҲҶй–ӢгҖӮ
3. зө•е°Қе®Ңж•ҙжҖ§пјҡзңӢиҰӢе№ҫеҲ—е°ұеҝ…й ҲијёеҮәе№ҫеҖӢ itemsгҖӮиӢҘжҹҗеҲ—еӯ—и·ЎжЁЎзіҠжҲ–иіҮж–ҷзјәеӨұпјҢд»Қй Ҳдҝқз•ҷи©ІеҲ—пјҢе°Үз„Ўжі•иҫЁиӯҳзҡ„ж¬„дҪҚеЎ«е…Ҙз©әеӯ—дёІжҲ– 0пјҢдёҰж–ј note иЁ»жҳҺгҖҢеӯ—и·ЎжЁЎзіҠз„Ўжі•еҲӨи®ҖгҖҚгҖӮдёҚеҸҜж“…иҮӘеҝҪз•ҘжҲ–ж•ҙдҪөжӯЈеёёиіҮж–ҷгҖӮ
4. з©әзҷҪеҲ—жҺ’йҷӨпјҡиЎЁж јдёӢж–№еҸӘжңү #N/A жҲ–е®Ңе…Ёз©әзҷҪдё”жІ’жңүе“ҒиҷҹгҖҒиҰҸж јгҖҒж•ёйҮҸзҡ„еҲ—пјҢдёҚз®—жҳҺзҙ°пјҢдёҚиҰҒијёеҮәгҖӮ

гҖҗдәҢгҖҒж¬„дҪҚжҘӯеӢҷиҰҸеүҮгҖ‘
1. е…ұйҖҡиіҮиЁҠпјҡиЎЁй ӯзҡ„гҖҢж—ҘжңҹгҖҚи«ӢзөұдёҖеҘ—з”ЁиҮіжүҖжңү itemsгҖӮиӢҘжҜҸеҲ—иЈҪд»Өе–®иҷҹзӣёеҗҢпјҢorder_no еЎ«дё»иҰҒиЈҪд»Өе–®иҷҹпјӣжҜҸеҲ—д»ҚйңҖеңЁ work_order_no еЎ«е…Ҙи©ІеҲ—иЈҪд»Өе–®иҷҹгҖӮ
2. ж—ҘжңҹпјҡиӢҘең–зүҮзӮәж°‘еңӢе№ҙпјҢдҫӢеҰӮ 115/2/13пјҢи«ӢиҪүжҲҗиҘҝе…ғ 2026-02-13T00:00:00+08:00гҖӮз„Ўжі•еҲӨи®ҖеүҮијёеҮәз©әеӯ—дёІгҖӮ
3. е“Ғиҷҹ part_noпјҡ
   - з¬¬дёҖеҖӢеӯ—е…ғеҝ…й ҲжҳҜиӢұж–ҮеӨ§еҜ« A-ZгҖӮ
   - е„Әе…ҲйҖІиЎҢ OCR иӘӨи®Җж ЎжӯЈпјҡйҰ–зўјиӢҘзӮә 0 дҝ®жӯЈзӮә Oпјӣ1 дҝ®жӯЈзӮә Iпјӣ5 дҝ®жӯЈзӮә Sпјӣ8 дҝ®жӯЈзӮә BгҖӮ
   - иӢҘж ЎжӯЈеҫҢд»Қз„Ўжі•зўәиӘҚйҰ–зўјзӮәиӢұж–ҮпјҢи«ӢијёеҮәз©әеӯ—дёІпјҢдёҰеңЁ note еҜ«жҳҺгҖҢе“Ғиҷҹй–Ӣй ӯйқһиӢұж–ҮжҲ–з„Ўжі•зўәиӘҚгҖҚгҖӮ
4. иҰҸж ј specпјҡеҢ…еҗ«е°әеҜёгҖҒжқҗиіӘгҖҒзҷҫеҲҶжҜ”гҖҒдёӯж–ҮжҸҸиҝ°жҲ–зү№ж®Ҡз¬ҰиҷҹпјҢи«Ӣе®Ңж•ҙдҝқз•ҷеҺҹе§Ӣж–Үеӯ—пјҢеӢҝзҝ»иӯҜгҖҒеӢҝжҲӘж–·гҖҒеӢҝеҗҲдҪөзӣёй„°еҲ—гҖӮ
5. ж•ёйҮҸж¬„дҪҚпјҡеҸӘијёеҮәж•ёеӯ—пјӣз„Ўжі•еҲӨи®ҖжҷӮијёеҮә 0гҖӮжүӢеҜ«ж•ёеӯ—иӢҘдҪҚж–јгҖҢеҜҰй ҳж•ёйҮҸгҖҚж¬„пјҢи«ӢеҲӨж–·зӮә received_qtyпјӣдёҚиҰҒжҠҠеӢҫеӢҫгҖҒеҲҶж•ёиЁ»иЁҳжҲ–жӢ¬иҷҹз•¶дҪңиҰҸж јгҖӮ
6. еӮҷиЁ»ж¬„пјҡи«Ӣдҝқз•ҷи©ІеҲ—еӮҷиЁ»пјӣжІ’жңүе•ҸйЎҢеүҮеЎ« OKгҖӮ

гҖҗдёүгҖҒијёеҮә JSON зөҗж§ӢгҖ‘
и«Ӣеҡҙж јйҒөе®Ҳд»ҘдёӢж јејҸпјҢзўәдҝқеҸҜиў« JSON.parse() и§Јжһҗпјҡ
{
  "total_detected_rows": 0,
  "order_no": "иЈҪд»Өе–®иҷҹжҲ–е–®ж“ҡиҷҹзўјпјҢз„Ўжі•еҲӨи®ҖеүҮз©әеӯ—дёІ",
  "date": "YYYY-MM-DDTHH:mm:ss+08:00пјҢз„Ўжі•еҲӨи®ҖеүҮз©әеӯ—дёІ",
  "items": [
    {
      "row_no": 1,
      "work_order_no": "и©ІеҲ—иЈҪд»Өе–®иҷҹпјӣиӢҘеҸӘжңүиЎЁй ӯиЈҪд»Өе–®иҷҹпјҢи«ӢеЎ«иЎЁй ӯеҖјпјӣз„Ўжі•еҲӨи®ҖеүҮз©әеӯ—дёІ",
      "part_no": "йҰ–зўјеҝ…зӮәиӢұж–ҮпјҢз„Ўжі•зўәиӘҚеүҮз©әеӯ—дёІ",
      "spec": "е®Ңж•ҙиҰҸж јжҸҸиҝ°пјҢз„Ўжі•еҲӨи®ҖеүҮз©әеӯ—дёІ",
      "defective_qty": 0,
      "request_qty": 0,
      "received_qty": 0,
      "note": "еӮҷиЁ»гҖҒз•°еёёеҺҹеӣ пјӣжІ’жңүе•ҸйЎҢеүҮеЎ« OK"
    }
  ]
}`;

return [{
  json: {
    startedAt: new Date().toISOString(),
    imageId: `${image.fileName || ''}|${image.fileSize || ''}`,
    operator,
    imageMeta: {
      fileName: image.fileName || '',
      mimeType: image.mimeType || 'image/jpeg',
      fileSize: image.fileSize || ''
    },
    prompt
  },
  binary: { image }
}];

function getGeminiText(payload) {
  for (const key of ['text', 'output', 'content', 'response', 'result', 'completion']) {
    if (typeof payload[key] === 'string' && payload[key].trim()) return payload[key].trim();
  }
  if (typeof payload.message?.content === 'string') return payload.message.content.trim();
  if (Array.isArray(payload.content?.parts)) {
    const text = payload.content.parts.find((part) => typeof part.text === 'string')?.text;
    if (text) return text.trim();
  }
  const text = payload.candidates?.[0]?.content?.parts?.find((part) => typeof part.text === 'string')?.text || '';
  return text.trim();
}

function parseJsonText(rawText) {
  if (!rawText) throw new Error('Gemini жңӘеӣһеӮіж–Үеӯ—е…§е®№');
  try {
    return JSON.parse(rawText);
  } catch (error) {
    const cleaned = rawText.replace(/^```json/i, '').replace(/^```/i, '').replace(/```$/i, '').trim();
    try {
      return JSON.parse(cleaned);
    } catch (innerError) {
      const match = rawText.match(/\{[\s\S]*\}/);
      if (!match) throw new Error('Gemini еӣһеӮійқһ JSON');
      return JSON.parse(match[0]);
    }
  }
}

const requestMeta = $('жә–еӮҷ Gemini и«ӢжұӮ').first().json;
const ocr = parseJsonText(getGeminiText($json));
const items = Array.isArray(ocr.items) ? ocr.items : [];
if (!items.length) throw new Error('OCR зөҗжһңжІ’жңү items жҳҺзҙ°');

return [{
  json: {
    ocr,
    operator: requestMeta.operator || {},
    imageMeta: requestMeta.imageMeta || {},
    startedAt: requestMeta.startedAt || '',
    imageId: requestMeta.imageId || ''
  }
}];

const ocrPayload = $('и§Јжһҗ OCR JSON').first().json;
const ocr = ocrPayload.ocr || {};
const operator = ocrPayload.operator || {};
const imageMeta = ocrPayload.imageMeta || {};
const masterItems = $input.all().map((item) => item.json);
const startedAt = ocrPayload.startedAt || new Date().toISOString();
const imageId = ocrPayload.imageId || '';
const batchId = `OCR-${startedAt.replace(/[-:.TZ]/g, '').slice(0, 14)}`;

function num(value) {
  const n = Number(String(value ?? '').replace(/,/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function normalize(value) {
  return String(value || '')
    .toUpperCase()
    .replace(/\s+/g, '')
    .replace(/[пјҢ,гҖӮ.;пјӣ:пјҡ()пјҲпјү\[\]гҖҗгҖ‘"'гҖҢгҖҚ]/g, '')
    .trim();
}

function getValue(obj, keys) {
  for (const key of keys) {
    if (obj?.[key] !== undefined && obj?.[key] !== null) return obj[key];
  }
  return '';
}

function isValidPartNo(value) {
  return /^[A-Za-z]/.test(String(value || '').trim());
}

function propVal(row, name) {
  const p = row?.properties?.[name];
  if (p) {
    switch (p.type) {
      case 'title': return (p.title || []).map((t) => t.plain_text).join('');
      case 'rich_text': return (p.rich_text || []).map((t) => t.plain_text).join('');
      case 'select': return p.select?.name || '';
      case 'number': return p.number ?? '';
      default: return '';
    }
  }
  for (const k of [name, 'property_' + name]) {
    if (row?.[k] !== undefined && row?.[k] !== null) return row[k];
  }
  return '';
}

const masterMap = new Map();
for (const master of masterItems) {
  const partNo = String(propVal(master, 'е“Ғиҷҹ') || master.name || '').trim();
  const spec = String(propVal(master, 'иҰҸж ј')).trim();
  if (partNo) masterMap.set(normalize(partNo), { partNo, spec });
}

let items = Array.isArray(ocr.items) ? ocr.items : [];
items = items.filter((item) => {
  const partNo = String(item.part_no || '').trim();
  const spec = String(item.spec || '').trim();
  return partNo || spec || item.note;
});

const rows = items.map((item, index) => {
  const partNo = String(item.part_no || '').trim();
  const spec = String(item.spec || '').trim();
  const workOrderNo = String(item.work_order_no || ocr.order_no || '').trim();
  const master = masterMap.get(normalize(partNo));
  const masterSpec = master?.spec || '';
  const orderNoCheck = Boolean(workOrderNo && workOrderNo !== 'жңӘеҲӨи®Җ');
  const partNoStartsOk = isValidPartNo(partNo);
  const partNoCheck = Boolean(partNoStartsOk && master);
  const specCheck = Boolean(master && normalize(masterSpec) && normalize(spec) && normalize(masterSpec) === normalize(spec));
  const notes = [];
  const errorTypes = [];
  if (!orderNoCheck) { notes.push('иЈҪд»Өе–®иҷҹжңӘеҲӨи®Җ'); errorTypes.push('иЈҪд»Өе–®иҷҹжңӘеҲӨи®Җ'); }
  if (!partNo) { notes.push('е“ҒиҷҹжңӘеҲӨи®Җ'); errorTypes.push('е“ҒиҷҹжңӘеҲӨи®Җ'); }
  if (partNo && !partNoStartsOk) { notes.push('е“Ғиҷҹй–Ӣй ӯйқһиӢұж–Ү'); errorTypes.push('е“Ғиҷҹй–Ӣй ӯйқһиӢұж–Ү'); }
  if (partNoStartsOk && !master) { notes.push('дё»жӘ”жҹҘз„Ўе“Ғиҷҹ'); errorTypes.push('дё»жӘ”жҹҘз„Ўе“Ғиҷҹ'); }
  if (!spec) { notes.push('иҰҸж јжңӘеҲӨи®Җ'); errorTypes.push('иҰҸж јжңӘеҲӨи®Җ'); }
  if (master && !specCheck) { notes.push(`иҰҸж јдёҚз¬Ұпјӣдё»жӘ”пјҡ${masterSpec || 'з©әеҖј'}`); errorTypes.push('иҰҸж јдёҚз¬Ұ'); }
  if (item.note && String(item.note).trim() !== 'OK') {
    notes.push(String(item.note));
    if (/жЁЎзіҠ|з„Ўжі•еҲӨи®Җ|дёҚжё…|зңӢдёҚжё…/.test(String(item.note))) errorTypes.push('еӯ—и·ЎжЁЎзіҠ');
  }
  const status = orderNoCheck && partNoCheck && specCheck ? 'OK' : 'з•°еёё';
  const ocrStatus = partNo && spec ? 'иҫЁиӯҳе®ҢжҲҗ' : 'иҫЁиӯҳдёҚе®Ңж•ҙ';

  return {
    rowNo: num(item.row_no) || index + 1,
    status,
    ocrStatus,
    orderNo: ocr.order_no || '',
    workOrderNo,
    date: ocr.date || '',
    partNo,
    spec,
    masterSpec,
    defectiveQty: num(item.defective_qty),
    requestQty: num(item.request_qty),
    receivedQty: num(item.received_qty),
    orderNoCheck,
    partNoCheck,
    specCheck,
    errorTypes,
    note: notes.join('пјӣ') || 'OK'
  };
});

const total = rows.length;
const abnormal = rows.filter((row) => row.status !== 'OK').length;

const completedAt = new Date().toISOString();
const processingSeconds = Math.max(0, Math.round((new Date(completedAt).getTime() - new Date(startedAt).getTime()) / 100) / 10);

return [{
  json: {
    batchId,
    imageId,
    startedAt,
    completedAt,
    processingSeconds,
    notifyStatus: 'еүҚз«ҜеӣһеӮі',
    operator,
    imageMeta,
    order_no: ocr.order_no || rows[0]?.workOrderNo || '',
    date: ocr.date || '',
    total,
    passed: total - abnormal,
    abnormal,
    rows
  }
}];

const compare = $('жҜ”е°Қ OCR иҲҮе“Ғй …дё»жӘ”').first().json;
const batchPage = $input.first().json;

return compare.rows.map((row) => ({
  json: {
    ...row,
    batchId: compare.batchId,
    batchUrl: batchPage.url || '',
    operator: compare.operator || {},
    summary: {
      order_no: compare.order_no,
      date: compare.date,
      total: compare.total,
      passed: compare.passed,
      abnormal: compare.abnormal
    }
  }
}));

const compare = $('жҜ”е°Қ OCR иҲҮе“Ғй …дё»жӘ”').first().json;
const details = $('жә–еӮҷжҳҺзҙ°еҜ«е…ҘиіҮж–ҷ').all().map((item) => item.json);
const createdPages = $input.all().map((item) => item.json);

return [{
  json: {
    ok: true,
    batchId: compare.batchId,
    order_no: compare.order_no,
    date: compare.date,
    total: compare.total,
    passed: compare.passed,
    abnormal: compare.abnormal,
    results: details.map((row, index) => ({
      status: row.status,
      partNo: row.partNo,
      spec: row.spec,
      defectiveQty: row.defectiveQty,
      requestQty: row.requestQty,
      receivedQty: row.receivedQty,
      note: row.note,
      notionUrl: createdPages[index]?.url || ''
    }))
  }
}];
